insert into public.script_categories (id, name)
values
  ('cc111111-1111-4111-8111-111111111111', '首次开发'),
  ('cc222222-2222-4222-8222-222222222222', '报价跟进'),
  ('cc333333-3333-4333-8333-333333333333', '催单'),
  ('cc444444-4444-4444-8444-444444444444', '客户维护'),
  ('cc555555-5555-4555-8555-555555555555', '价格异议')
on conflict (id) do update set name = excluded.name;

insert into public.scripts (id, category_id, title, content_zh, content_id, tags)
values
  ('bb111111-1111-4111-8111-111111111111', 'cc111111-1111-4111-8111-111111111111', '首次开发 - 工厂介绍', '您好，我们是印尼 HOMY 海绵工厂，主要生产沙发、床垫、包装和工业用途海绵。请问您目前采购哪一类海绵？我可以先发规格和价格范围给您参考。', 'Halo, kami HOMY, pabrik spons di Indonesia. Kami memproduksi spons untuk sofa, kasur, kemasan, dan industri. Boleh tahu jenis spons apa yang sedang Anda cari?', array['首次联系','工厂介绍','WhatsApp']),
  ('bb111112-1111-4111-8111-111111111112', 'cc111111-1111-4111-8111-111111111111', '首次开发 - 询问采购需求', '您好，看到贵司有家具/床垫相关业务。想了解一下您常用的海绵密度、尺寸和月采购量大概是多少？我们可以按您的规格提供样品和批量报价。', 'Halo, saya melihat perusahaan Anda bergerak di furniture/kasur. Boleh tahu densitas spons, ukuran, dan estimasi pembelian bulanan yang biasa digunakan? Kami bisa siapkan sampel dan harga grosir sesuai spesifikasi.', array['需求挖掘','家具','床垫']),
  ('bb111113-1111-4111-8111-111111111113', 'cc111111-1111-4111-8111-111111111111', '首次开发 - 展会后跟进', '您好，很高兴在展会上认识您。根据您提到的沙发坐垫需求，我们整理了 25D、30D、35D 三个密度方案，方便的话我发给您对比一下。', 'Halo, senang bertemu Anda di pameran. Berdasarkan kebutuhan cushion sofa yang Anda sebutkan, kami sudah siapkan opsi densitas 25D, 30D, dan 35D. Jika berkenan, saya kirimkan untuk dibandingkan.', array['展会','方案','沙发']),
  ('bb222221-2222-4222-8222-222222222221', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 确认是否查看', '您好，昨天发您的报价和产品参数是否方便看过？如果规格方向合适，我们建议先安排样品，确认手感和密度后再进入批量订单。', 'Halo, apakah penawaran dan spesifikasi yang kami kirim kemarin sudah sempat dicek? Jika arahnya cocok, kami sarankan mulai dari sampel untuk konfirmasi feel dan densitas.', array['报价','样品','跟进']),
  ('bb222222-2222-4222-8222-222222222222', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 补充装柜信息', '补充说明一下，这个报价可以按 20GP/40HQ 装柜优化。如果您确认目标数量，我们可以重新核算装柜方案和更准确的到港成本。', 'Sebagai tambahan, penawaran ini bisa dioptimalkan untuk loading 20GP/40HQ. Jika jumlah target sudah jelas, kami bisa hitung ulang rencana loading dan estimasi biaya sampai tujuan dengan lebih akurat.', array['装柜','外贸','成本']),
  ('bb222223-2222-4222-8222-222222222223', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 推荐替代规格', '如果当前规格预算偏高，我们也可以提供接近手感的替代密度方案，在保证使用效果的前提下降低单价。需要我帮您做一版对比报价吗？', 'Jika spesifikasi saat ini di atas budget, kami bisa tawarkan opsi densitas alternatif dengan feel yang mendekati namun harga lebih efisien. Apakah perlu saya buatkan perbandingan harga?', array['替代方案','降本','报价']),
  ('bb333331-3333-4333-8333-333333333331', 'cc333333-3333-4333-8333-333333333333', '催单 - 样品反馈后推进', '您好，想跟进一下样品测试结果。若手感和回弹符合要求，我们可以先锁定当前原料价格，并为您预留生产排期。', 'Halo, saya ingin follow up hasil test sampel. Jika feel dan rebound sudah sesuai, kami bisa bantu lock harga bahan saat ini dan reservasi jadwal produksi untuk Anda.', array['样品','排期','催单']),
  ('bb333332-3333-4333-8333-333333333332', 'cc333333-3333-4333-8333-333333333333', '催单 - 报价有效期提醒', '提醒您一下，本次报价有效期到本周五。由于原料价格近期波动，如果您计划近期下单，建议先确认数量，我们可以优先安排。', 'Saya ingin mengingatkan bahwa penawaran ini berlaku sampai Jumat minggu ini. Karena harga bahan baku sedang bergerak, jika Anda berencana order dalam waktu dekat, sebaiknya jumlah dikonfirmasi dulu agar bisa kami prioritaskan.', array['有效期','原料波动','订单']),
  ('bb333333-3333-4333-8333-333333333333', 'cc333333-3333-4333-8333-333333333333', '催单 - 生产档期紧张', '目前工厂下周生产档期已经比较满。如果您这批货有交期要求，建议我们今天先确认 PI 和订金，以免影响出货时间。', 'Saat ini jadwal produksi minggu depan cukup penuh. Jika shipment ini punya target waktu, sebaiknya PI dan deposit dikonfirmasi hari ini agar jadwal pengiriman tidak terganggu.', array['交期','PI','订金']),
  ('bb444441-4444-4444-8444-444444444441', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 到货后关怀', '您好，看到这批货已经到港/到仓了。请问包装、数量和产品状态都正常吗？如果生产使用中有任何反馈，我们会第一时间协助处理。', 'Halo, saya melihat barang sudah tiba di pelabuhan/gudang. Apakah packing, jumlah, dan kondisi produk semuanya baik? Jika ada feedback saat produksi, kami siap bantu segera.', array['售后','到货','维护']),
  ('bb444442-4444-4444-8444-444444444442', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 复购提醒', '您好，上次采购的海绵预计已经使用一段时间了。请问库存还充足吗？如果需要补货，我们可以按上次规格快速更新报价和交期。', 'Halo, stok spons dari pembelian sebelumnya mungkin sudah mulai digunakan. Apakah stok masih cukup? Jika perlu repeat order, kami bisa update harga dan lead time berdasarkan spesifikasi terakhir.', array['复购','库存','老客户']),
  ('bb444443-4444-4444-8444-444444444443', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 新品推荐', '我们近期有一款更适合沙发坐垫的高回弹海绵，回弹稳定、压缩变形更低。若您方便，我可以寄一小块样品给您测试。', 'Kami baru memiliki opsi HR foam yang cocok untuk cushion sofa, rebound stabil dan compression set lebih rendah. Jika Anda berkenan, saya bisa kirim potongan sampel kecil untuk diuji.', array['新品','高回弹','样品']),
  ('bb555551-5555-4555-8555-555555555551', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 强调稳定供货', '理解您在比较价格。我们的报价包含稳定密度、准时交付和售后支持，适合长期批量采购。若您有目标价，我可以帮您调整规格或数量来匹配预算。', 'Saya paham Anda sedang membandingkan harga. Harga kami mencakup densitas stabil, pengiriman tepat waktu, dan dukungan purna jual. Jika ada target harga, kami bisa sesuaikan spesifikasi atau kuantitas.', array['价格','谈判','长期合作']),
  ('bb555552-5555-4555-8555-555555555552', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 解释密度差异', '同样叫 30D，不同工厂的实际密度、回弹和耐久性会有差异。我们可以提供切样对比，您能更直观看到支撑力和使用寿命的区别。', 'Walaupun sama-sama disebut 30D, densitas aktual, rebound, dan durability tiap pabrik bisa berbeda. Kami bisa kirim sampel potongan untuk perbandingan agar perbedaan support dan umur pakai lebih jelas.', array['密度','品质','对比']),
  ('bb555553-5555-4555-8555-555555555553', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 阶梯报价', '如果您能确认更高数量，我们可以按阶梯价重新核算。比如样品单、小柜和整柜价格会不同，我可以给您做三档报价对比。', 'Jika kuantitas bisa ditingkatkan, kami bisa hitung ulang dengan harga bertingkat. Harga untuk sampel, LCL, dan full container berbeda; saya bisa buatkan tiga opsi untuk dibandingkan.', array['阶梯价','整柜','预算'])
on conflict (id) do update set
  category_id = excluded.category_id,
  title = excluded.title,
  content_zh = excluded.content_zh,
  content_id = excluded.content_id,
  tags = excluded.tags;

insert into public.scripts (id, category_id, title, content_zh, content_id, tags)
values
  ('bb111114-1111-4111-8111-111111111114', 'cc111111-1111-4111-8111-111111111111', '首次开发 - WhatsApp 简短开场', '您好，我是 HOMY 海绵工厂的销售，看到您可能有沙发/床垫海绵需求。我们在印尼生产不同密度和尺寸的海绵，可以按批量采购提供报价。方便了解一下您目前主要采购什么规格吗？', 'Halo, saya sales dari pabrik spons HOMY. Saya melihat mungkin ada kebutuhan spons sofa/kasur. Kami produksi berbagai densitas dan ukuran di Indonesia, bisa siapkan harga grosir. Boleh tahu spesifikasi yang biasa Anda beli?', array['首次联系','WhatsApp','规格']),
  ('bb111115-1111-4111-8111-111111111115', 'cc111111-1111-4111-8111-111111111111', '首次开发 - 网站询盘回复', '您好，感谢您通过网站联系 HOMY。为了给您准确报价，请您发一下海绵用途、密度、尺寸、数量和目的港/收货城市，我们会尽快提供产品建议和价格。', 'Halo, terima kasih sudah menghubungi HOMY melalui website. Untuk penawaran yang akurat, mohon kirim penggunaan spons, densitas, ukuran, quantity, dan kota tujuan/pelabuhan. Kami segera siapkan rekomendasi dan harga.', array['网站询盘','报价','信息收集']),
  ('bb111116-1111-4111-8111-111111111116', 'cc111111-1111-4111-8111-111111111111', '首次开发 - LinkedIn 开发', '您好，我们是印尼海绵制造商 HOMY，服务家具、床垫、包装和工业客户。如果您正在寻找稳定供应商，我可以发一份产品目录和常用密度价格范围给您参考。', 'Halo, kami HOMY, manufaktur spons di Indonesia untuk furniture, mattress, packaging, dan industri. Jika Anda sedang mencari supplier stabil, saya bisa kirim katalog produk dan kisaran harga densitas umum.', array['LinkedIn','目录','供应商']),
  ('bb111117-1111-4111-8111-111111111117', 'cc111111-1111-4111-8111-111111111111', '首次开发 - 社媒客户开场', '您好，看到您在社媒上有家具/软包产品展示，我们工厂可以供应坐垫、靠背和包装海绵。若您方便，我可以先按您常用尺寸做一版推荐规格。', 'Halo, saya melihat produk furniture/soft furnishing Anda di media sosial. Pabrik kami bisa supply spons cushion, backrest, dan packaging. Jika berkenan, saya bisa rekomendasikan spesifikasi sesuai ukuran umum Anda.', array['社媒','家具','推荐规格']),
  ('bb111118-1111-4111-8111-111111111118', 'cc111111-1111-4111-8111-111111111111', '首次开发 - OEM 工厂合作', '您好，HOMY 可以按客户品牌和规格长期供货，支持样品确认、批量生产和稳定交期。请问贵司是否有 OEM 或固定规格采购计划？', 'Halo, HOMY bisa supply jangka panjang sesuai brand dan spesifikasi customer, termasuk sampel, produksi massal, dan lead time stabil. Apakah perusahaan Anda memiliki rencana OEM atau pembelian spesifikasi tetap?', array['OEM','长期合作','工厂']),

  ('bb222224-2222-4222-8222-222222222224', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 第二天跟进', '您好，昨天的报价您是否方便初步看过？如果价格或规格需要调整，我可以根据您的目标预算重新做一版更合适的方案。', 'Halo, apakah penawaran kemarin sudah sempat dilihat? Jika harga atau spesifikasi perlu disesuaikan, saya bisa buatkan opsi yang lebih sesuai dengan target budget Anda.', array['报价','第二天','预算']),
  ('bb222225-2222-4222-8222-222222222225', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 询问目标价', '为了更快匹配方案，想确认一下您这批货的目标价区间是多少？我们可以从密度、厚度、数量和包装方式几个方向帮您优化成本。', 'Agar lebih cepat cocokkan solusi, boleh tahu target harga untuk shipment ini? Kami bisa bantu optimasi biaya dari densitas, ketebalan, quantity, dan metode packing.', array['目标价','降本','谈判']),
  ('bb222226-2222-4222-8222-222222222226', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 确认贸易条款', '当前报价按 FOB 计算。如果您需要 CIF 或到门价格，请告诉我目的港/地址和预计数量，我可以补充运费并更新总成本。', 'Penawaran saat ini berdasarkan FOB. Jika membutuhkan CIF atau door-to-door, mohon kirim port/alamat tujuan dan estimasi quantity, saya akan tambahkan freight dan update total cost.', array['FOB','CIF','运费']),
  ('bb222227-2222-4222-8222-222222222227', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 样品前确认', '在寄样前，我想再确认密度、厚度和手感要求，避免样品方向偏差。确认后我们会按最接近量产标准准备样品。', 'Sebelum kirim sampel, saya ingin konfirmasi ulang densitas, ketebalan, dan feel yang dibutuhkan agar arah sampel tepat. Setelah fix, kami siapkan sampel sesuai standar produksi massal.', array['样品','规格确认','量产']),
  ('bb222228-2222-4222-8222-222222222228', 'cc222222-2222-4222-8222-222222222222', '报价跟进 - 多规格对比', '我可以为您做 2-3 个密度/厚度组合对比，包括单价、装柜量和适用场景，这样更容易判断哪一款最适合您的产品。', 'Saya bisa buatkan perbandingan 2-3 kombinasi densitas/ketebalan, termasuk unit price, loading quantity, dan aplikasi produk agar lebih mudah memilih opsi terbaik.', array['多规格','对比','装柜']),

  ('bb333334-3333-4333-8333-333333333334', 'cc333333-3333-4333-8333-333333333333', '催单 - 订金确认', '您好，这边想确认一下订金安排。订金到账后我们可以立即锁定原料和生产排期，避免后续价格或交期变化。', 'Halo, kami ingin konfirmasi jadwal deposit. Setelah deposit diterima, kami bisa langsung lock bahan dan jadwal produksi agar harga dan lead time tidak berubah.', array['订金','排期','原料']),
  ('bb333335-3333-4333-8333-333333333335', 'cc333333-3333-4333-8333-333333333333', '催单 - 保留生产档期', '这批订单如果本周确认，我们可以优先保留生产档期。若延后确认，可能需要顺延到下一轮排产。', 'Jika order ini dikonfirmasi minggu ini, kami bisa prioritaskan jadwal produksi. Jika konfirmasi mundur, jadwal kemungkinan masuk batch produksi berikutnya.', array['生产档期','订单','交期']),
  ('bb333336-3333-4333-8333-333333333336', 'cc333333-3333-4333-8333-333333333333', '催单 - 月底装柜提醒', '如果您希望月底前装柜，建议今天确认 PI 和数量。我们需要预留切割、包装和装柜时间，避免影响船期。', 'Jika ingin loading sebelum akhir bulan, sebaiknya PI dan quantity dikonfirmasi hari ini. Kami perlu siapkan waktu cutting, packing, dan loading agar jadwal kapal tidak terganggu.', array['装柜','船期','PI']),
  ('bb333337-3333-4333-8333-333333333337', 'cc333333-3333-4333-8333-333333333333', '催单 - 样品通过转大货', '样品如果已经通过测试，我们建议尽快确认大货数量。这样可以沿用当前样品标准，并减少重新确认规格的时间。', 'Jika sampel sudah lolos test, kami sarankan segera konfirmasi quantity mass production. Dengan begitu standar sampel bisa langsung dipakai dan waktu konfirmasi spesifikasi lebih singkat.', array['样品通过','大货','规格']),
  ('bb333338-3333-4333-8333-333333333338', 'cc333333-3333-4333-8333-333333333333', '催单 - 老客户补货推进', '按照上次采购周期，您这边库存可能快到补货时间了。需要我们先按原规格更新价格和最快交期吗？', 'Berdasarkan siklus pembelian sebelumnya, stok Anda mungkin sudah mendekati waktu refill. Apakah perlu kami update harga dan lead time tercepat berdasarkan spesifikasi lama?', array['老客户','补货','复购']),

  ('bb444444-4444-4444-8444-444444444444', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 使用反馈回访', '您好，想了解一下上批海绵在生产使用中的表现，手感、回弹和切割尺寸是否都符合预期？您的反馈会帮助我们稳定后续供货。', 'Halo, kami ingin mengetahui performa spons batch sebelumnya saat digunakan produksi. Apakah feel, rebound, dan ukuran cutting sudah sesuai? Feedback Anda membantu kami menjaga supply berikutnya.', array['反馈','品质','维护']),
  ('bb444445-4444-4444-8444-444444444445', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 库存预警', '根据上次订单数量和时间，您现在可能接近安全库存线。若需要补货，我可以提前帮您排产并锁定当前价格。', 'Berdasarkan quantity dan tanggal order terakhir, stok Anda mungkin sudah mendekati safety stock. Jika perlu refill, saya bisa bantu booking produksi dan lock harga saat ini.', array['库存预警','补货','价格']),
  ('bb444446-4444-4444-8444-444444444446', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 推荐新规格', '我们最近有一款更适合高端坐垫的密度组合，支撑力更好、压缩变形更低。您下次开发新品时可以考虑测试。', 'Kami punya kombinasi densitas baru untuk cushion premium, support lebih baik dan compression set lebih rendah. Saat Anda develop produk baru, opsi ini bisa dipertimbangkan untuk test.', array['新规格','高端坐垫','测试']),
  ('bb444447-4444-4444-8444-444444444447', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 月度采购确认', '您好，本月采购计划是否已经确定？如果有预计数量，我们可以提前准备原料，帮助您缩短交期。', 'Halo, apakah rencana pembelian bulan ini sudah ada? Jika quantity estimasi sudah diketahui, kami bisa siapkan bahan lebih awal agar lead time lebih singkat.', array['月度计划','原料','交期']),
  ('bb444448-4444-4444-8444-444444444448', 'cc444444-4444-4444-8444-444444444444', '客户维护 - 质量稳定提醒', '为了保持后续批次稳定，建议继续使用上次确认的密度和工艺参数。如果您要调整手感，我们可以先做小样确认。', 'Untuk menjaga stabilitas batch berikutnya, kami sarankan tetap memakai densitas dan parameter proses yang sudah disetujui. Jika ingin ubah feel, kami bisa buat sampel kecil dulu.', array['质量稳定','工艺','小样']),

  ('bb555554-5555-4555-8555-555555555554', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 拆解成本', '这款海绵价格主要由密度、原料、切割损耗和包装体积决定。若要降价，我们可以一起看哪一项可以调整，而不是直接牺牲质量。', 'Harga spons ini terutama dipengaruhi densitas, bahan baku, loss cutting, dan volume packing. Jika ingin efisiensi, kita bisa lihat bagian mana yang bisa disesuaikan tanpa langsung menurunkan kualitas.', array['成本拆解','质量','价格']),
  ('bb555555-5555-4555-8555-555555555555', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 和低价供应商对比', '如果您有其他供应商报价，我们可以帮您对比密度、尺寸公差、包装和交期。很多低价差异来自实际密度或包装标准不同。', 'Jika ada penawaran supplier lain, kami bisa bantu bandingkan densitas, toleransi ukuran, packing, dan lead time. Perbedaan harga rendah sering berasal dari densitas aktual atau standar packing yang berbeda.', array['竞品对比','低价','密度']),
  ('bb555556-5555-4555-8555-555555555556', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 数量换价格', '如果单价需要再优化，建议提高单次采购数量或合并规格生产。这样可以降低换线和包装成本，我们也更容易给到折扣。', 'Jika unit price perlu lebih efisien, sebaiknya quantity sekali beli dinaikkan atau produksi beberapa ukuran digabung. Ini bisa menurunkan setup dan packing cost, sehingga diskon lebih memungkinkan.', array['数量','折扣','生产效率']),
  ('bb555557-5555-4555-8555-555555555557', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 付款条件换优惠', '若您可以接受更快订金或较短账期，我们可以申请更好的价格条件。这样双方现金流和生产安排都会更稳定。', 'Jika Bapak/Ibu bisa menerima deposit lebih cepat atau termin pembayaran lebih pendek, kami bisa ajukan kondisi harga yang lebih baik. Cash flow dan jadwal produksi juga lebih stabil untuk kedua pihak.', array['付款条件','优惠','现金流']),
  ('bb555558-5555-4555-8555-555555555558', 'cc555555-5555-4555-8555-555555555555', '价格异议 - 分档方案', '我建议准备标准版、经济版和高端版三档方案。这样您可以根据不同客户群选择，而不是只用一个价格去覆盖所有需求。', 'Saya sarankan siapkan tiga opsi: standard, ekonomis, dan premium. Dengan begitu Anda bisa pilih sesuai segmen customer, bukan memakai satu harga untuk semua kebutuhan.', array['分档方案','预算','客户群'])
on conflict (id) do update set
